// Logic: direction (PLACE/LEND → KLB chuyển tiền ra; TAKE/BORROW → nhận tiền vào)
// Chỉ hiển thị deals có requires_international_settlement = true
func (q *Queries) ListMMInterbankPendingSettlement(ctx context.Context, arg ListMMInterbankPendingSettlementParams) ([]ListMMInterbankPendingSettlementRow, error) {
	rows, err := q.db.Query(ctx, listMMInterbankPendingSettlement, arg.Limit, arg.Offset)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []ListMMInterbankPendingSettlementRow{}
	for rows.Next() {
		var i ListMMInterbankPendingSettlementRow
		if err := rows.Scan(
			&i.ID,
			&i.DealNumber,
			&i.TicketNumber,
			&i.CounterpartyID,
			&i.BranchID,
			&i.CurrencyCode,
			&i.InternalSsiID,
			&i.CounterpartySsiID,
			&i.Direction,
			&i.PrincipalAmount,
			&i.InterestRate,
			&i.DayCountConvention,
			&i.TradeDate,
			&i.EffectiveDate,
			&i.TenorDays,
			&i.MaturityDate,
			&i.InterestAmount,
			&i.MaturityAmount,
			&i.HasCollateral,
			&i.CollateralCurrency,
			&i.CollateralDescription,
			&i.RequiresInternationalSettlement,
			&i.Status,
			&i.Note,
			&i.ClonedFromID,
			&i.CancelReason,
			&i.CancelRequestedBy,
			&i.CancelRequestedAt,
			&i.CreatedAt,
			&i.CreatedBy,
			&i.UpdatedAt,
			&i.UpdatedBy,
			&i.DeletedAt,
			&i.CounterpartyCode,
			&i.CounterpartyName,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

