// Interest calculation formula (for reference — computed in application):
// ACT_365: interest = principal × rate/100 × tenor_days / 365
// ACT_360: interest = principal × rate/100 × tenor_days / 360
// ACT_ACT: interest = principal × rate/100 × tenor_days / year_basis
//
//	(year_basis = 365 or 366, depending on whether period spans Feb 29)
func (q *Queries) SetMMInterbankCancelRequest(ctx context.Context, arg SetMMInterbankCancelRequestParams) (MmInterbankDeal, error) {
	row := q.db.QueryRow(ctx, setMMInterbankCancelRequest,
		arg.CancelRequestedBy,
		arg.ID,
		arg.CancelReason,
		arg.Status,
	)
	var i MmInterbankDeal
	err := row.Scan(
		&i.ID,
		&i.DealNumber,
		&i.TicketNumber,
		&i.CounterpartyID,
		&i.BranchID,
		&i.CurrencyCode,
		&i.InternalSsiID,
		&i.CounterpartySsiID,
		&i.Direction,
		&i.PrincipalAmount,
		&i.InterestRate,
		&i.DayCountConvention,
		&i.TradeDate,
		&i.EffectiveDate,
		&i.TenorDays,
		&i.MaturityDate,
		&i.InterestAmount,
		&i.MaturityAmount,
		&i.HasCollateral,
		&i.CollateralCurrency,
		&i.CollateralDescription,
		&i.RequiresInternationalSettlement,
		&i.Status,
		&i.Note,
		&i.ClonedFromID,
		&i.CancelReason,
		&i.CancelRequestedBy,
		&i.CancelRequestedAt,
		&i.CreatedAt,
		&i.CreatedBy,
		&i.UpdatedAt,
		&i.UpdatedBy,
		&i.DeletedAt,
	)
	return i, err
}

